#include <signal.h>

// Interface of the signal function:
sighandler_t signal(int signum, sighandler_t handler);

// signum  = signal type to configure
// handler = SIG_DFL | SIG_IGN | pointer to user function
// Returns: previous handler, or SIG_ERR on error

// The handler function type:
typedef void (*sighandler_t)(int);
// i.e., a function returning void, with an int argument

// sig_ex2.c - Ignoring SIGINT and SIGQUIT
#include <stdio.h>
#include <signal.h>
#include <unistd.h>

int main() {
    // Ignore SIGINT (Ctrl+C) and SIGQUIT (Ctrl+\)
    signal(SIGINT, SIG_IGN);
    signal(SIGQUIT, SIG_IGN);

    printf("Try pressing Ctrl+C or Ctrl+\\ ...\n");
    while (1) {
        printf("Running...\n");
        sleep(1);
    }
    return 0;
}

// sig_ex3.c - Custom signal handler + restoring default
#include <stdio.h>
#include <signal.h>
#include <unistd.h>

void my_handler(int signum) {
    printf("\nCaught signal %d\n", signum);
    // Restore default handler so next signal terminates
    signal(signum, SIG_DFL);
}

int main() {
    // Set custom handler for SIGINT and SIGQUIT
    signal(SIGINT, my_handler);
    signal(SIGQUIT, my_handler);

    printf("First Ctrl+C prints message, second terminates.\n");
    while (1) {
        printf("Running...\n");
        sleep(1);
    }
    return 0;
}

