// sig_ex4.c - Blocking SIGINT during a critical section
#include <stdio.h>
#include <signal.h>
#include <unistd.h>

int main() {
    sigset_t block_set, old_set;

    sigemptyset(&block_set);
    sigaddset(&block_set, SIGINT);

    // Block SIGINT
    sigprocmask(SIG_BLOCK, &block_set, &old_set);

    printf("SIGINT blocked for 5 seconds...\n");
    sleep(5);  // Critical section

    // Unblock SIGINT (pending signals delivered now)
    sigprocmask(SIG_SETMASK, &old_set, NULL);
    printf("SIGINT unblocked.\n");

    sleep(5);
    return 0;
}

#include <unistd.h>

int pause(void);
// Effect: suspends execution until a signal arrives
// Always returns -1 with errno set to EINTR

#include <signal.h>

int sigsuspend(const sigset_t *set);
// Effect: atomically replaces signal mask with *set,
//         then suspends until a signal not in *set arrives
// Returns: always -1 (errno = EINVAL, EFAULT, or EINTR)

// Example: suspend execution waiting for SIGQUIT
#include <stdio.h>
#include <signal.h>

void handler(int sig) {
    printf("Received SIGQUIT\n");
}

int main() {
    sigset_t mask;

    signal(SIGQUIT, handler);

    // Block all signals except SIGQUIT
    sigfillset(&mask);
    sigdelset(&mask, SIGQUIT);

    printf("Waiting for SIGQUIT (Ctrl+\\)...\n");
    sigsuspend(&mask);  // Atomically unblock SIGQUIT and wait

    printf("Resumed after signal.\n");
    return 0;
}
